<script setup lang="ts">
definePageMeta({ layout: 'default', alias: ['/connections', '/integrations'] })
const { preview } = usePreActionGuidance()
const supabase = useSupabaseClient<any>()
const connectors = ref<any[]>([]), loading = ref(true), error = ref(''), query = ref(''), category = ref('All')
const secretProvider = ref<any>(null), secret = ref(''), label = ref('Primary'), saving = ref(false)
const mcpOpen = ref(false), mcpName = ref(''), mcpUrl = ref(''), mcpSaving = ref(false)
const requestedIds = ref(new Set<string>()), requestingAll = ref(false), requestNotice = ref('')
const categories = computed(() => ['All', ...new Set(connectors.value.map(item => item.category))])
const filtered = computed(() => connectors.value.filter(item => category.value === 'All' || item.category === category.value).filter(item => !query.value || `${item.name} ${item.summary} ${item.capabilities.join(' ')}`.toLowerCase().includes(query.value.toLowerCase())))
const recommended = computed(() => connectors.value.filter(item => item.recommended))
const recommendedReady = computed(() => recommended.value.filter(item => item.connected_accounts?.length).length)
const connectedCount = computed(() => connectors.value.filter(item => item.connected_accounts?.length).length)
const availableCount = computed(() => connectors.value.filter(item => item.configured && !item.connected_accounts?.length).length)
const pendingCount = computed(() => requestedIds.value.size)
const suiteProgress = computed(() => recommended.value.length ? Math.round((recommendedReady.value / recommended.value.length) * 100) : 0)
function statusLabel(item: any) { return item.connected_accounts?.length ? 'Connected' : requestedIds.value.has(item.id) ? 'Activation requested' : item.configured ? 'Ready to connect' : 'Setup required' }
function statusClass(item: any) { return item.connected_accounts?.length ? 'connected' : requestedIds.value.has(item.id) ? 'pending' : item.configured ? 'ready' : 'setup' }
function actionLabel(item: any) { return item.connected_accounts?.length ? 'Add account' : item.configured ? 'Connect securely' : requestedIds.value.has(item.id) ? 'Request queued' : 'Request connection' }
async function authedFetch<T = any>(url: string, options: any = {}) { const { data: { session } } = await supabase.auth.getSession(); return $fetch<T>(url, { ...options, headers: { ...(options.headers || {}), ...(session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {}) } }) }
async function load() { loading.value = true; error.value = ''; try { const result = await authedFetch<any>('/api/connectors'); connectors.value = result.connectors || [] } catch (e: any) { error.value = e?.data?.message || e?.message || 'Connector registry is unavailable.' } finally { loading.value = false } }
function connect(item: any) { if (!item.configured) { requestConnections([item]); return } if (item.auth === 'api-key') { secretProvider.value = item; return } if (item.auth === 'mcp-oauth') { mcpOpen.value = true; return } preview({ product: 'orchestrator', domain: 'users_access', actionType: `connector:authorize:${item.id}`, intent: `Authorize ${item.name}`, reversibility: 'reversible', blastRadius: 'single', confidence: .9, affectedApps: 1, evidence: [{ source: 'OAuth authorization code flow with PKCE where supported', confidence: .95 }, { source: `requested scopes: ${item.defaultScopes.join(', ') || 'provider default'}`, confidence: .9 }], ifNotDone: `${item.name} remains unavailable to models and workflows.` }, async () => { const result = await authedFetch<any>('/api/connectors/oauth/start', { method: 'POST', body: { provider: item.id, scopes: item.defaultScopes } }); window.location.assign(result.authorization_url) }) }
function requestConnections(items: any[]) { const pending = items.filter(item => !item.connected_accounts?.length && !requestedIds.value.has(item.id)); if (!pending.length) return; preview({ product: 'orchestrator', domain: 'users_access', actionType: 'connector:activation-request', intent: `Request activation for ${pending.map(item => item.name).join(', ')}`, reversibility: 'reversible', blastRadius: pending.length > 3 ? 'fleet' : 'small', confidence: .94, affectedApps: pending.length, evidence: pending.map(item => ({ source: `${item.name}: ${item.auth}`, confidence: .9 })), ifNotDone: 'These specialist capabilities remain unavailable to automatic routes.' }, async () => { requestingAll.value = pending.length > 1; requestNotice.value = ''; try { const result = await authedFetch<any>('/api/connectors/request', { method: 'POST', body: { providers: pending.map(item => item.id) } }); requestedIds.value = new Set([...requestedIds.value, ...pending.map(item => item.id)]); requestNotice.value = `${result.requested.length} connection${result.requested.length === 1 ? '' : 's'} queued for secure activation. Madeus will request consent or credentials only when required.` } finally { requestingAll.value = false } }) }
function connectMcp() { if (!mcpUrl.value) return; preview({ product: 'orchestrator', domain: 'users_access', actionType: 'connector:authorize:remote-mcp', intent: `Discover and authorize ${mcpName.value || mcpUrl.value}`, reversibility: 'reversible', blastRadius: 'single', confidence: .86, affectedApps: 1, evidence: [{ source: 'MCP protected-resource metadata', confidence: .9 }, { source: 'Resource-bound OAuth with PKCE', confidence: .95 }], ifNotDone: 'The remote MCP tools remain unavailable to governed model routes.' }, async () => { mcpSaving.value = true; try { const found = await authedFetch<any>('/api/connectors/mcp/discover', { method: 'POST', body: { name: mcpName.value, server_url: mcpUrl.value } }); const auth = await authedFetch<any>('/api/connectors/mcp/authorize', { method: 'POST', body: { server_id: found.server.id, scopes: found.server.scopes_supported } }); window.location.assign(auth.authorization_url) } finally { mcpSaving.value = false } }) }
function saveKey() { const item = secretProvider.value; if (!item || !secret.value) return; preview({ product: 'orchestrator', domain: 'users_access', actionType: `connector:credential:${item.id}`, intent: `Connect ${item.name}`, reversibility: 'reversible', blastRadius: 'small', confidence: .92, affectedApps: 1, estimatedCostUsd: 0, evidence: [{ source: 'Server-encrypted credential vault', confidence: .95 }, { source: 'Provider-scoped API credential', confidence: .85 }], ifNotDone: `${item.name} cannot be selected for routed work.` }, async () => { saving.value = true; try { await authedFetch('/api/connectors/api-key', { method: 'POST', body: { provider: item.id, secret: secret.value, label: label.value } }); secret.value = ''; secretProvider.value = null; await load() } finally { saving.value = false } }) }
function revoke(account: any) { preview({ product: 'orchestrator', domain: 'users_access', actionType: `connector:revoke:${account.provider}`, intent: `Revoke ${account.provider} connection`, reversibility: 'hard_to_reverse', blastRadius: 'small', confidence: .95, evidence: [{ source: `connector account ${account.id}`, confidence: 1 }], ifNotDone: 'The connector retains its current delegated access.' }, async () => { await authedFetch(`/api/connectors/${account.id}/revoke`, { method: 'POST' }); await load() }) }
onMounted(load)
</script>

<template>
  <main class="connections-page">
    <header class="connections-hero">
      <div><span class="kicker">Capability connections</span><h1>Bring your best tools.<br><em>Madeus coordinates the rest.</em></h1><p>Connect each account once. Madeus chooses the right tool only when it improves the outcome, requests the minimum access, and records every use.</p></div>
      <aside v-if="!loading && !error" class="connection-stats">
        <div><strong>{{ connectedCount }}</strong><span>Connected</span></div><div><strong>{{ availableCount }}</strong><span>Ready now</span></div><div><strong>{{ pendingCount }}</strong><span>Pending</span></div>
      </aside>
    </header>

    <div class="connections-shell">
      <section v-if="!loading && !error" class="suite-card">
        <div class="suite-copy"><span>Recommended production suite</span><h2>{{ recommendedReady }} of {{ recommended.length }} critical connections ready</h2><p>Selected for broad workflow coverage and verified API access. Activation includes least-privilege configuration, consent, health checks, and routing validation.</p></div>
        <div class="suite-action"><div class="progress-label"><span>Coverage</span><b>{{ suiteProgress }}%</b></div><div class="progress-track"><i :style="`width:${suiteProgress}%`" /></div><button :disabled="requestingAll || recommendedReady === recommended.length" @click="requestConnections(recommended.filter(item => !item.connected_accounts?.length))">{{ requestingAll ? 'Requesting…' : recommendedReady === recommended.length ? 'Suite connected' : 'Activate remaining suite' }}</button></div>
        <div v-if="requestNotice" class="request-notice">{{ requestNotice }}</div>
      </section>

      <section class="trust-strip"><b>Secure by design</b><span>Provider consent</span><span>Minimum scopes</span><span>Encrypted credentials</span><span>Revocable access</span><span>Audited use</span></section>

      <details v-if="!loading && !error" class="managed-routing">
        <summary><span><b>Madeus-managed connection quality</b><small>Routing, health, permissions, and fallbacks are optimized automatically.</small></span><i>View safeguards</i></summary>
        <div><p><b>Use only when useful.</b> A connected tool is selected only when it improves the requested outcome.</p><p><b>Least privilege.</b> Madeus requests the minimum scopes and records delegated access.</p><p><b>Resilient by default.</b> Health checks and fallback routes keep work moving when a provider is unavailable.</p></div>
      </details>

      <div class="toolbar">
        <label class="search"><span>⌕</span><input v-model="query" type="search" placeholder="Search tools, models, and capabilities…"></label>
        <div class="category-list"><button v-for="item in categories" :key="item" :class="{ active: category === item }" @click="category = item">{{ item }}</button></div>
      </div>

      <div v-if="loading" class="empty-state">Loading your connection fabric…</div>
      <div v-else-if="error" class="empty-state error">{{ error }} <button @click="load">Retry</button></div>
      <div v-else-if="!filtered.length" class="empty-state">No connections match this search.</div>
      <section v-else class="connector-grid">
        <article v-for="item in filtered" :key="item.id" class="connector-card">
          <div class="card-head">
            <span class="provider-icon">{{ item.icon }}</span>
            <div class="card-title"><div><span>{{ item.category }}</span><i v-if="item.recommended">{{ item.tier || 'Core' }}</i></div><h2>{{ item.name }}</h2></div>
            <span class="status" :class="statusClass(item)"><i />{{ statusLabel(item) }}</span>
          </div>
          <p class="summary">{{ item.summary }}</p>
          <details class="connector-details"><summary>Capabilities &amp; access <span>{{ item.capabilities.length }} capabilities</span></summary><div v-if="item.workflow" class="best-for"><span>Best for</span><p>{{ item.workflow }}</p></div><div class="capabilities"><span v-for="cap in item.capabilities" :key="cap">{{ cap }}</span></div><small>{{ item.auth }} · {{ item.risk }} sensitivity</small></details>
          <div v-if="item.connected_accounts.length" class="accounts"><div v-for="account in item.connected_accounts" :key="account.id"><span><b>{{ account.label || 'Connected account' }}</b><small>{{ account.status }} · {{ account.scopes.length }} scopes</small></span><button @click="revoke(account)">Revoke</button></div></div>
          <footer><button class="primary-action" :disabled="requestedIds.has(item.id) && !item.configured" @click="connect(item)">{{ actionLabel(item) }} <span>↗</span></button><a v-if="item.documentationUrl" :href="item.documentationUrl" target="_blank" rel="noopener">Docs</a></footer>
        </article>
      </section>
    </div>

    <div v-if="secretProvider" class="modal-backdrop" @mousedown.self="secretProvider = null"><form class="connector-modal" @submit.prevent="saveKey"><span class="kicker">Encrypted credential</span><h2>Connect {{ secretProvider.name }}</h2><p>The credential goes directly to the Madeus server, is encrypted with AES-256-GCM, and is never returned to the browser.</p><label>Account label<input v-model="label" autocomplete="off"></label><label>API credential<input v-model="secret" type="password" required minlength="12" autocomplete="new-password"></label><div><button type="button" @click="secretProvider = null">Cancel</button><button :disabled="saving">Review connection</button></div></form></div>
    <div v-if="mcpOpen" class="modal-backdrop" @mousedown.self="mcpOpen = false"><form class="connector-modal" @submit.prevent="connectMcp"><span class="kicker">Custom connection</span><h2>Connect remote MCP</h2><p>Madeus discovers authorization metadata, rejects private-network targets, and requests a resource-bound token with PKCE.</p><label>Display name<input v-model="mcpName" placeholder="Production tools"></label><label>HTTPS server URL<input v-model="mcpUrl" type="url" required pattern="https://.*" placeholder="https://mcp.example.com"></label><div><button type="button" @click="mcpOpen = false">Cancel</button><button :disabled="mcpSaving">Review and discover</button></div></form></div>
  </main>
</template>

