dfe8e1;color:#466753}@media(max-width:920px){.connector-grid{grid-template-columns:1fr}.managed-routing>div{grid-template-columns:1fr}}@media(max-width:620px){.managed-routing summary{align-items:flex-start;flex-direction:column}}
